namespace ReviewApp.Helpers
{
    public static class FormattingHelper
    {
        public static IHtmlString FormatReviewContent(string content)
        {
            if (string.IsNullOrEmpty(content))
            {
                return new HtmlString(string.Empty);
            }

            content = HttpUtility.HtmlEncode(content);
            
            content = System.Text.RegularExpressions.Regex.Replace(
                content, 
                @"\*\*(.+?)\*\*", 
                "<strong>$1</strong>"
            );
            
            content = System.Text.RegularExpressions.Regex.Replace(
                content, 
                @"\*(.+?)\*", 
                "<em>$1</em>"
            );
            
            content = System.Text.RegularExpressions.Regex.Replace(
                content, 
                @"__(.+?)__", 
                "<strong>$1</strong>"
            );
            
            content = System.Text.RegularExpressions.Regex.Replace(
                content, 
                @"_(.+?)_", 
                "<em>$1</em>"
            );
            
            content = content.Replace("\n", "<br />");

            return new HtmlString(content);
        }
    }
}

namespace ReviewApp.Controllers
{
    public class ProductController : Controller
    {
        private ReviewDbContext db = new ReviewDbContext();

        public ActionResult Details(int id)
        {
            var product = db.Products
                .Include(p => p.Reviews)
                .FirstOrDefault(p => p.ProductId == id);

            if (product == null)
            {
                return HttpNotFound();
            }

            var viewModel = new ProductViewModel
            {
                ProductId = product.ProductId,
                Name = product.Name,
                Description = product.Description,
                Price = product.Price,
                Reviews = product.Reviews
                    .OrderByDescending(r => r.CreatedDate)
                    .Select(r => new ReviewViewModel
                    {
                        ReviewId = r.ReviewId,
                        UserName = r.UserName,
                        Title = r.Title,
                        Content = r.Content,
                        Rating = r.Rating,
                        CreatedDate = r.CreatedDate
                    })
                    .ToList(),
                TotalReviews = product.Reviews.Count,
                AverageRating = product.Reviews.Any() ? product.Reviews.Average(r => r.Rating) : 0
            };

            return View(viewModel);
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult SubmitReview(int productId, string userName, string title, string content, int rating)
        {
            if (ModelState.IsValid)
            {
                var review = new Review
                {
                    ProductId = productId,
                    UserName = userName,
                    Title = title,
                    Content = content,
                    Rating = rating,
                    CreatedDate = DateTime.Now
                };

                db.Reviews.Add(review);
                db.SaveChanges();

                return RedirectToAction("Details", new { id = productId });
            }

            return RedirectToAction("Details", new { id = productId });
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                db.Dispose();
            }
            base.Dispose(disposing);
        }
    }
}